bool check_initrd(const char _initrd_begin[], const char _initrd_end[]) {
    if (_initrd_begin == _initrd_end) {
        cprintf("Warning: No Initrd!\n");
        return 0;
    }
    cprintf("Initrd: 0x%08x - 0x%08x, size: 0x%08x\n", _initrd_begin,
            _initrd_end - 1, _initrd_end - _initrd_begin);
    return 1;
}

static int ramdisk_read(struct ide_device *dev, size_t secno, void *dst,
                        size_t nsecs) {
    nsecs = MIN(nsecs, dev->size - secno);
    if (nsecs < 0) return -1;
    memcpy(dst, (void *)(dev->iobase + secno * SECTSIZE), nsecs * SECTSIZE);
    return 0;
}

static int ramdisk_write(struct ide_device *dev, size_t secno, const void *src,
                         size_t nsecs) {
    nsecs = MIN(nsecs, dev->size - secno);
    if (nsecs < 0) return -1;
    memcpy((void *)(dev->iobase + secno * SECTSIZE), src, nsecs * SECTSIZE);
    return 0;
}

void ramdisk_init(int devno, struct ide_device *dev) {
    memset(dev, 0, sizeof(struct ide_device));
    char *_initrd_begin;
    char *_initrd_end;
    if (devno == SWAP_DEV_NO) {
        _initrd_begin = _binary_bin_swap_img_start;
        _initrd_end = _binary_bin_swap_img_end;
    } else if (devno == DISK0_DEV_NO) {
        _initrd_begin = _binary_bin_sfs_img_start;
        _initrd_end = _binary_bin_sfs_img_end;
    } else {
        panic("Device Not Found");
    }

    if (check_initrd(_initrd_begin, _initrd_end)) {
        dev->valid = 1;
        dev->sets = ~0;
        dev->size = (unsigned int)(_initrd_end - _initrd_begin) / SECTSIZE;
        dev->iobase = (uintptr_t)_initrd_begin;
        strcpy(dev->model, "KERN_INITRD");
        dev->read_secs = ramdisk_read;
        dev->write_secs = ramdisk_write;
    }
}

void sd_init()
{
    cardinfo.active = 0;

    // Part 1: Hardware infrastructure configuration
    sdcard_pin_mapping_init();
    sdcard_gpiohs_init();
    sdcard_spi_init();

    // Part 2: SD protocol(SPI Mode)
    sd_SPI_mode_prepare();

    if(sd_switch_to_SPI_mode() != 0)
        return;
    if(sd_negotiate_voltage() != 0)
        return;
    if(sd_set_SDXC_capacity() != 0)
        return;
    if(sd_query_capacity_status() != 0)
        return;

    SD_HIGH_SPEED_ENABLE();

    if(sd_get_cardinfo(&cardinfo) != 0)
        return;

    // Part 3: Read/Write test
//    sd_test();
    cprintf("Successfully initialize SD card!\n");
}

uint8_t sd_read_sector(uint8_t *data_buff, uint32_t sector, uint32_t count)
{
    uint8_t dummy_crc[2], multiple;
    if (count == 1){
        multiple = 0;
        sd_send_cmd(SD_CMD17, sector, 0);
    } else{
        multiple = 1;
        sd_send_cmd(SD_CMD18, sector, 0);
    }

    uint32_t result = sd_get_R1_response();
    if (result != SD_TRANS_MODE_RESULT_OK) {
        cprintf("Read sector(s) CMD error! result = %d\n", result);
        return SD_ERROR_RES;
    }

    while (count)
    {
        result = sd_get_R1_response();
        if (result != SD_START_DATA_READ_RESPONSE) {
            cprintf("Data read response error! result = %d\n", result);
            return SD_ERROR_RES;
        }

        sd_read_data(data_buff, SECTOR_SIZE);
        sd_read_data(dummy_crc, 2);

        data_buff += SECTOR_SIZE;
        count--;
    }

    sd_end_cmd();
    if (multiple){
        sd_send_cmd(SD_CMD12, 0, 0);
        sd_get_R1_response();
        sd_end_cmd();
        sd_end_cmd();
    }

    if (count > 0) {
        cprintf("Not all sectors are read!\n");
        return SD_ERROR_RES;
    }

    return 0;
}

uint8_t sd_write_sector(uint8_t *data_buff, uint32_t sector, uint32_t count)
{
    assert(((uint32_t)data_buff) % 4 == 0);
    uint8_t token[2] = {0xFF, 0x00}, dummpy_crc[2] = {0xFF, 0xFF};

    if (count == 1){
        token[1] = SD_START_DATA_SINGLE_BLOCK_WRITE_TOKEN;
        sd_send_cmd(SD_CMD24, sector, 0);
    } else{
        token[1] = SD_START_DATA_MULTIPLE_BLOCK_WRITE_TOKEN;
        sd_send_cmd(SD_ACMD23, count, 0);
        sd_get_R1_response();
        sd_end_cmd();
        sd_send_cmd(SD_CMD25, sector, 0);
    }

    if (sd_get_R1_response() != SD_TRANS_MODE_RESULT_OK) {
        cprintf("Write sector(s) CMD error!\n");
        return SD_ERROR_RES;
    }

        while (count)
    {
        sd_write_data(token, 2);
        sd_write_data(data_buff, SECTOR_SIZE);
        sd_write_data(dummpy_crc, 2);

        if (sd_get_data_write_response() != SD_TRANS_MODE_RESULT_OK) {
            cprintf("Data write response error!\n");
            return SD_ERROR_RES;
        }

        data_buff += SECTOR_SIZE;
        count--;
    }

    sd_end_cmd();
    sd_end_cmd();

    if (count > 0) {
        cprintf("Not all sectors are written!\n");
        return SD_ERROR_RES;
    }

    return 0;
}

