int sysctl_clock_enable(sysctl_clock_t clock)
{
    if (clock >= SYSCTL_CLOCK_MAX)
        return -1;
    sysctl_clock_bus_end_en(clock,1);
    sysctl_clock_device_end_en(clock,1);
    return 0;
}

