static struct file *
get_fd_array(void) {
    struct files_struct *filesp = current->filesp;
    assert(filesp != NULL && files_count(filesp) > 0);
    return filesp->fd_array;
}

void
fd_array_init(struct file *fd_array) {
    int fd;
    struct file *file = fd_array;
    for (fd = 0; fd < FILES_STRUCT_NENTRY; fd ++, file ++) {
        file->open_count = 0;
        file->status = FD_NONE, file->fd = fd;
    }
}

static int
fd_array_alloc(int fd, struct file **file_store) {
//    panic("debug");
    struct file *file = get_fd_array();
    if (fd == NO_FD) {
        for (fd = 3; fd < FILES_STRUCT_NENTRY; fd ++, file ++) {
            if (file->status == FD_NONE) {
                goto found;
            }
        }
        return -E_MAX_OPEN;
    }
    else {
        //cprintf("in fs_array_dup nentry:%d\n", FILES_STRUCT_NENTRY);
        if (testfd(fd)) {
            file += fd;
            if (file->status == FD_NONE) {
                goto found;
            }
            return -E_BUSY;
        }
        return -E_INVAL;
    }
found:
    assert(fopen_count(file) == 0);
    file->status = FD_INIT, file->node = NULL;
    *file_store = file;
    return 0;
}

static void
fd_array_free(struct file *file) {
    assert(file->status == FD_INIT || file->status == FD_CLOSED);
    assert(fopen_count(file) == 0);
    if (file->status == FD_CLOSED) {
        vfs_close(file->node);
    }
    file->status = FD_NONE;
}

static void
fd_array_acquire(struct file *file) {
    assert(file->status == FD_OPENED);
    fopen_count_inc(file);
}

static void
fd_array_release(struct file *file) {
    assert(file->status == FD_OPENED || file->status == FD_CLOSED);
    assert(fopen_count(file) > 0);
    if (fopen_count_dec(file) == 0) {
        fd_array_free(file);
    }
}

void
fd_array_open(struct file *file) {
    assert(file->status == FD_INIT && file->node != NULL);
    file->status = FD_OPENED;
    fopen_count_inc(file);
}

void
fd_array_close(struct file *file) {
    assert(file->status == FD_OPENED);
    assert(fopen_count(file) > 0);
    file->status = FD_CLOSED;
    if (fopen_count_dec(file) == 0) {
        fd_array_free(file);
    }
}

void
fd_array_dup(struct file *to, struct file *from) {
    //cprintf("[fd_array_dup]from fd=%d, to fd=%d\n",from->fd, to->fd);
    assert(to->status == FD_INIT && from->status == FD_OPENED);
    to->pos = from->pos;
    to->readable = from->readable;
    to->writable = from->writable;
    struct inode *node = from->node;
    vop_ref_inc(node), vop_open_inc(node);
    to->node = node;
    fd_array_open(to);
}

static inline int
fd2file(int fd, struct file **file_store) {
    if (testfd(fd)) {
        struct file *file = get_fd_array() + fd;
        if (file->status == FD_OPENED && file->fd == fd) {
            *file_store = file;
            return 0;
        }
    }
    return -E_INVAL;
}

bool
file_testfd(int fd, bool readable, bool writable) {
    int ret;
    struct file *file;
    if ((ret = fd2file(fd, &file)) != 0) {
        return 0;
    }
    if (readable && !file->readable) {
        cprintf("in file_testfd.fd%d read:%d\n", fd, file->readable);
        return 0;
    }
    if (writable && !file->writable) {
        cprintf("in file_testfd.fd%d write:%d\n", fd, file->writable);
        return 0;
    }
    return 1;
}

int
file_open(char *path, uint32_t open_flags) {
    bool readable = 0, writable = 0;
    switch (open_flags & O_ACCMODE) {
    case O_RDONLY: readable = 1; break;
    case O_WRONLY: writable = 1; break;
    case O_RDWR:
    case O_CREAT:
        readable = writable = 1;
        break;
    default:
        return -E_INVAL;
    }
    int ret;
    struct file *file;
    if ((ret = fd_array_alloc(NO_FD, &file)) != 0) {
        return ret;
    }

    struct inode *node;
    if ((ret = vfs_open(path, open_flags, &node)) != 0) {
        fd_array_free(file);
        return ret;
    }
    //cprintf("in file_open. vfs_open succeed\n");

    file->pos = 0;
    if (open_flags & O_APPEND) {
        struct stat __stat, *stat = &__stat;
        if ((ret = vop_fstat(node, stat)) != 0) {
            vfs_close(node);
            fd_array_free(file);
            return ret;
        }
        file->pos = stat->st_size;
        //cprintf("[file_write]file->pos:%d\n", file->pos);
    }
    if (open_flags & O_CLOEXEC) {
        file->close_on_exec = 1;
    }
    file->node = node;
    file->readable = readable;
    file->writable = writable;
    file->flags = open_flags;
    fd_array_open(file);
    //cprintf("in file_open:get write:%d\n", file->writable);
    return file->fd;
}

int
file_openat(int fd_dir, char* path, uint64_t open_flags)  {
    bool readable = 0, writable = 0;
    switch (open_flags & O_ACCMODE) {
    case O_RDONLY: readable = 1; break;
    case O_WRONLY: writable = 1; break;
    case O_RDWR:
    case O_CREAT:
        readable = writable = 1;
        break;
    default:
        return -E_INVAL;
    }

    int ret;
    struct file *file, *dict;
    if ((ret = fd_array_alloc(NO_FD, &file)) != 0) {
        return ret;
    }

    // find the dict inode
    if ((ret = fd2file(fd_dir, &dict)) != 0) {
        return ret;
    }
    struct inode *dir = dict->node;
    struct inode *node;
    if ((ret = vfs_openat(dir, path, open_flags, &node)) != 0) {
        fd_array_free(file);
        return ret;
    }
    file->pos = 0;
    if (open_flags & O_APPEND) {
        struct stat __stat, *stat = &__stat;
        if ((ret = vop_fstat(node, stat)) != 0) {
            vfs_close(node);
            fd_array_free(file);
            return ret;
        }
        file->pos = stat->st_size;
    }
    if(open_flags & O_CLOEXEC) {
        file->close_on_exec = 1;
    }
    file->node = node;
    file->readable = readable;
    file->writable = writable;
    file->flags = open_flags;
    fd_array_open(file);
    //cprintf("in file_openat:get write:%d\n", file->writable);
    return file->fd;
}

int
file_close(int fd) {
    int ret;
    struct file *file;
    if ((ret = fd2file(fd, &file)) != 0) {
        return ret;
    }
    fd_array_close(file);
    return 0;
}

int
file_read(int fd, void *base, size_t len, size_t *copied_store) {
    int ret;
    struct file *file;
    *copied_store = 0;
    if ((ret = fd2file(fd, &file)) != 0) {
        return ret;
    }
    //cprintf("in file_read. find the inode:%d, pos:%d, status:%d\n", file->node->in_info.__sfs_inode_info.ino, file->pos, file->status);
    if (!file->readable) {
        return -E_INVAL;
    }
    fd_array_acquire(file);

    struct iobuf __iob, *iob = iobuf_init(&__iob, base, len, file->pos);
    ret = vop_read(file->node, iob);

    size_t copied = iobuf_used(iob);
    if (file->status == FD_OPENED) {
        file->pos += copied;
    }
    *copied_store = copied;
    fd_array_release(file);
    return ret;
}

int
file_write(int fd, void *base, size_t len, size_t *copied_store) {
    int ret;
    struct file *file;
    *copied_store = 0;
    if ((ret = fd2file(fd, &file)) != 0) {
        return ret;
    }
    if (!file->writable) {
        return -E_INVAL;
    }
    fd_array_acquire(file);

    struct iobuf __iob, *iob = iobuf_init(&__iob, base, len, file->pos);
    ret = vop_write(file->node, iob);

    size_t copied = iobuf_used(iob);
    if (file->status == FD_OPENED) {
        file->pos += copied;
    }
    *copied_store = copied;
    fd_array_release(file);
    return ret;
}

int
file_seek(int fd, off_t pos, int whence) {
    struct stat __stat, *stat = &__stat;
    int ret;
    struct file *file;
    if ((ret = fd2file(fd, &file)) != 0) {
        return ret;
    }
    fd_array_acquire(file);

    switch (whence) {
    case LSEEK_SET: break;
    case LSEEK_CUR: pos += file->pos; break;
    case LSEEK_END:
        if ((ret = vop_fstat(file->node, stat)) == 0) {
            pos += stat->st_size;
        }
        break;
    default: ret = -E_INVAL;
    }

    if (ret == 0) {
        if ((ret = vop_tryseek(file->node, pos)) == 0) {
            file->pos = pos;
        }
//    cprintf("file_seek, pos=%d, whence=%d, ret=%d\n", pos, whence, ret);
    }
    fd_array_release(file);
    return ret;
}

int
file_fstat(int fd, struct stat *stat) {
    int ret;
    struct file *file;
    if ((ret = fd2file(fd, &file)) != 0) {
        return ret;
    }
    fd_array_acquire(file);
    ret = vop_fstat(file->node, stat);
    fd_array_release(file);
    return ret;
}

int
file_newfstatat(int dirfd, char* path, struct stat * stat, int flags){
    int fd = file_openat(dirfd, path, flags);
    int ret = file_fstat(fd, stat);
    file_close(fd);
    return ret;
}

int
file_fsync(int fd) {
    int ret;
    struct file *file;
    if ((ret = fd2file(fd, &file)) != 0) {
        return ret;
    }
    fd_array_acquire(file);
    ret = vop_fsync(file->node);
    fd_array_release(file);
    return ret;
}

int
file_getdirentry(int fd, struct dirent *direntp) {
    int ret;
    struct file *file;
    if ((ret = fd2file(fd, &file)) != 0) {
        return ret;
    }
    fd_array_acquire(file);
    while(direntp->d_off <= 512){
        //cprintf("[file_getdirentry] name:%s len:%d offset:%d\n", direntp->d_name, sizeof(direntp->d_name), direntp->d_off);
        struct iobuf __iob, *iob = iobuf_init(&__iob, direntp->d_name, sizeof(direntp->d_name), direntp->d_off);
        if ((ret = vop_getdirentry(file->node, iob)) == 0) {
            direntp->d_off += iobuf_used(iob);
        }
        else break;
        direntp->d_reclen++;
    }
    fd_array_release(file);
    return ret;
}

int
file_dup(int fd1, int fd2) {
    int ret;
    struct file *file1, *file2;
    if ((ret = fd2file(fd1, &file1)) != 0) {
        cprintf("in file_dup. bad fd.\n");
        return ret;
    }
    if ((ret = fd_array_alloc(fd2, &file2)) != 0) {
        cprintf("in file_dup. bad fd alloc.\n");
        return ret;
    }
    fd_array_dup(file2, file1);
    return file2->fd;
}

int
file_dup3(int fd1, int fd2, int flags){
    int ret;
    struct file *file1, *file2;
    if ((ret = fd2file(fd1, &file1)) != 0) {
        cprintf("in file_dup. bad fd.\n");
        return ret;
    }
    if(flags){
        file1->close_on_exec = 1;
    }
    if ((ret = fd_array_alloc(fd2, &file2)) != 0) {
        cprintf("in file_dup. bad fd alloc.\n");
        return ret;
    }
    fd_array_dup(file2, file1);
    return file2->fd;
}

int
file_pipe(int fd[]) {
    int ret;
    struct file *file[2] = {NULL, NULL};
    if ((ret = fd_array_alloc(NO_FD, &file[0])) != 0) {
        goto failed_cleanup;
    }
    if ((ret = fd_array_alloc(NO_FD, &file[1])) != 0) {
        goto failed_cleanup;
    }
    //cprintf("[file_pipe] file0:%d,file1:%d\n", file[0]->fd, file[1]->fd);
    if ((ret = pipe_open(&(file[0]->node), &(file[1]->node))) != 0) {
        goto failed_cleanup;
    }
    file[0]->pos = 0;
    file[0]->readable = 1, file[0]->writable = 0;
    fd_array_open(file[0]);

    file[1]->pos = 0;
    file[1]->readable = 0, file[1]->writable = 1;
    fd_array_open(file[1]);

    fd[0] = file[0]->fd, fd[1] = file[1]->fd;
    return 0;

failed_cleanup:
    if (file[0] != NULL) {
        fd_array_free(file[0]);
    }
    if (file[1] != NULL) {
        fd_array_free(file[1]);
    }
    return ret;
}

int file_fcntl(int fd, int cmd, uint64_t flags){
    switch (cmd){
        case F_DUPFD:
            return file_dup(fd, NO_FD);
        case F_GETFD:
            return file_getflags(fd);
        case F_SETFD:
            return file_setflags(fd, flags);
        case F_GETFL:
            return file_getstatus(fd);
        case F_SETFL:
            return file_setstatus(fd, flags);
        default:
            cprintf("file control function %d hasn't realized.\n", cmd);
            return -1;
    }
}

int file_getflags(int fd){
    int ret = 0;
    struct file * file;
    if((ret = fd2file(fd, &file)) != 0){
        return ret;
    }
    return file->flags;
}

int file_setflags(int fd, uint64_t flags) {
    int ret = 0;
    struct file * file;
    if((ret = fd2file(fd, &file)) != 0){
        return ret;
    }
    file->flags = flags;
    switch (flags & O_ACCMODE) {
    case O_RDONLY: file->readable = 1; break;
    case O_WRONLY: file->writable = 1; break;
    case O_RDWR:
        file->readable = file->writable = 1;    break;
    default:
        return -E_INVAL;
    }
    if(flags & O_CLOEXEC)
        file->close_on_exec = 1;
    return ret;
}

int file_getstatus(int fd){
    int ret = 0;
    struct file * file;
    if((ret = fd2file(fd, &file)) != 0){
        return ret;
    }
    return file->status;
}

int file_setstatus(int fd, uint64_t flags){
    cprintf("set status is unavailable.\n");
    return -E_INVAL;
}

int
file_renameat(int olddirfd, char *oldpath, int newdirfd, char *newpath){
    int ret;
    struct file *olddict, *newdict;

    // find the oldict inode
    if ((ret = fd2file(olddirfd, &olddict)) != 0) {
        return ret;
    }

    if ((ret = fd2file(newdirfd, &newdict)) != 0) {
        return ret;
    }
    struct inode *oldnode, *newnode;
    oldnode = olddict->node;
    newnode = newdict->node;
    fd_array_acquire(olddict);
    fd_array_acquire(newdict);
    if((ret = vfs_renameat(oldnode, oldpath, newnode, newpath)) != 0){
        return ret;
    }
    fd_array_release(newdict);
    fd_array_release(olddict);

    return -E_INVAL;
}

struct file {
    enum {
        FD_NONE, FD_INIT, FD_OPENED, FD_CLOSED,
    } status;
    bool readable;
    bool writable;
    bool close_on_exec;
    int fd;
    off_t pos;
    struct inode *node;
    int open_count;
    uint64_t flags;
}

static inline int
fopen_count(struct file *file) {
    return file->open_count;
}

static inline int
fopen_count_inc(struct file *file) {
    file->open_count += 1;
    return file->open_count;
}

static inline int
fopen_count_dec(struct file *file) {
    file->open_count -= 1;
    return file->open_count;
}

void
fs_init(void) {
    vfs_init();
    dev_init();
    sfs_init();
    pipe_init();
}

void
fs_cleanup(void) {
    vfs_cleanup();
}

void
lock_files(struct files_struct *filesp) {
    down(&(filesp->files_sem));
}

void
unlock_files(struct files_struct *filesp) {
    up(&(filesp->files_sem));
}

struct files_struct *
files_create(void) {
    //cprintf("[files_create]\n");
    //static_assert((int)FILES_STRUCT_NENTRY > 128);
    struct files_struct *filesp;
    if ((filesp = kmalloc(sizeof(struct files_struct) + FILES_STRUCT_BUFSIZE)) != NULL) {
        filesp->pwd = NULL;
        filesp->fd_array = (void *)(filesp + 1);
        filesp->files_count = 0;
        sem_init(&(filesp->files_sem), 1);
        fd_array_init(filesp->fd_array);
    }
    return filesp;
}

void
files_destroy(struct files_struct *filesp) {
//    cprintf("[files_destroy]\n");
    assert(filesp != NULL && files_count(filesp) == 0);
    if (filesp->pwd != NULL) {
        vop_ref_dec(filesp->pwd);
    }
    int i;
    struct file *file = filesp->fd_array;
    for (i = 0; i < FILES_STRUCT_NENTRY; i ++, file ++) {
        if (file->status == FD_OPENED) {
            fd_array_close(file);
        }
        assert(file->status == FD_NONE);
    }
    kfree(filesp);
}

void
files_closeall(struct files_struct *filesp) {
//    cprintf("[files_closeall]\n");
    assert(filesp != NULL && files_count(filesp) > 0);
    int i;
    struct file *file = filesp->fd_array;
    //skip the stdin & stdout
    for (i = 2, file += 2; i < FILES_STRUCT_NENTRY; i ++, file ++) {
        if (file->status == FD_OPENED) {
            fd_array_close(file);
        }
    }
}

void 
files_cloexec(struct files_struct *filesp) {
    assert(filesp != NULL && files_count(filesp) > 0);
    int i;
    struct file *file = filesp->fd_array;
    //skip the stdin & stdout
    for (i = 2, file += 2; i < FILES_STRUCT_NENTRY; i ++, file ++) {
        if (file->status == FD_OPENED && file->close_on_exec == 1) {
            fd_array_close(file);
        }
    }
}

int
dup_files(struct files_struct *to, struct files_struct *from) {
//    cprintf("[dup_fs]\n");
    assert(to != NULL && from != NULL);
    assert(files_count(to) == 0 && files_count(from) > 0);
    if ((to->pwd = from->pwd) != NULL) {
        vop_ref_inc(to->pwd);
    }
    int i;
    struct file *to_file = to->fd_array, *from_file = from->fd_array;
    for (i = 0; i < FILES_STRUCT_NENTRY; i ++, to_file ++, from_file ++) {
        if (from_file->status == FD_OPENED) {
            /* alloc_fd first */
            to_file->status = FD_INIT;
            fd_array_dup(to_file, from_file);
        }
    }
    return 0;
}

struct files_struct {
    struct inode *pwd;      // inode of present working directory
    struct file *fd_array;  // opened files array
    int files_count;        // the number of opened files
    semaphore_t files_sem;  // lock protect sem
}

static inline int
files_count(struct files_struct *filesp) {
    return filesp->files_count;
}

static inline int
files_count_inc(struct files_struct *filesp) {
    filesp->files_count += 1;
    return filesp->files_count;
}

static inline int
files_count_dec(struct files_struct *filesp) {
    filesp->files_count -= 1;
    return filesp->files_count;
}

struct iobuf *
iobuf_init(struct iobuf *iob, void *base, size_t len, off_t offset) {
    iob->io_base = base;
    iob->io_offset = offset;
    iob->io_len = len;
    iob->io_resid = len;
    return iob;
}

int
iobuf_move(struct iobuf *iob, void *data, size_t len, bool m2b, size_t *copiedp) {
    size_t alen;
    if ((alen = iob->io_resid) > len) {
        alen = len;
    }
    if (alen > 0) {
        void *src = iob->io_base, *dst = data;
        if (m2b) {
            void *tmp = src;
            src = dst, dst = tmp;
        }
        memmove(dst, src, alen);
        iobuf_skip(iob, alen), len -= alen;
    }
    if (copiedp != NULL) {
        *copiedp = alen;
    }
    return (len == 0) ? 0 : -E_NO_MEM;
}

int
iobuf_move_zeros(struct iobuf *iob, size_t len, size_t *copiedp) {
    size_t alen;
    if ((alen = iob->io_resid) > len) {
        alen = len;
    }
    if (alen > 0) {
        memset(iob->io_base, 0, alen);
        iobuf_skip(iob, alen), len -= alen;
    }
    if (copiedp != NULL) {
        *copiedp = alen;
    }
    return (len == 0) ? 0 : -E_NO_MEM;
}

void
iobuf_skip(struct iobuf *iob, size_t n) {
    assert(iob->io_resid >= n);
    iob->io_base += n, iob->io_offset += n, iob->io_resid -= n;
}

struct iobuf {
    void *io_base;     // the base addr of buffer (used for Rd/Wr)
    off_t io_offset;   // current Rd/Wr position in buffer, will have been incremented by the amount transferred
    size_t io_len;     // the length of buffer  (used for Rd/Wr)
    size_t io_resid;   // current resident length need to Rd/Wr, will have been decremented by the amount transferred.
}

static int
copy_path(char **to, const char *from) {
    struct mm_struct *mm = current->mm;
    char *buffer;
    if ((buffer = kmalloc(FS_MAX_FPATH_LEN + 1)) == NULL) {
        return -E_NO_MEM;
    }
    lock_mm(mm);
    if (!copy_string(mm, buffer, from, FS_MAX_FPATH_LEN + 1)) {
        unlock_mm(mm);
        goto failed_cleanup;
    }
    unlock_mm(mm);
    *to = buffer;
    return 0;

failed_cleanup:
    kfree(buffer);
    return -E_INVAL;
}

