int
sysfile_read(int fd, void *base, size_t len) {
    struct mm_struct *mm = current->mm;
    if (len == 0) {
        return 0;
    }
    if (!file_testfd(fd, 1, 0)) {
        return -E_INVAL;
    }
    void *buffer;
    if ((buffer = kmalloc(IOBUF_SIZE)) == NULL) {
        return -E_NO_MEM;
    }

    int ret = 0;
    size_t copied = 0, alen;
    while (len != 0) {
        if ((alen = IOBUF_SIZE) > len) {
            alen = len;
        }
        ret = file_read(fd, buffer, alen, &alen);
        if (alen != 0) {
            lock_mm(mm);
            {
                if (copy_to_user(mm, base, buffer, alen)) {
                    assert(len >= alen);
                    base += alen, len -= alen, copied += alen;
                }
                else if (ret == 0) {
                    ret = -E_INVAL;
                }
            }
            unlock_mm(mm);
        }
        if (ret != 0 || alen == 0) {
            goto out;
        }
    }

out:
    kfree(buffer);
    if (copied != 0) {
        return copied;
    }
    return ret;
}

int
sysfile_readv(int fd, const struct iovec * iov, int iovcnt){
    struct mm_struct *mm = current->mm;
    if (iovcnt == 0) {
        return 0;
    }
    if (!file_testfd(fd, 1, 0)) {
        return -E_INVAL;
    }
    void *buffer;
    if ((buffer = kmalloc(IOBUF_SIZE)) == NULL) {
        return -E_NO_MEM;
    }
    int ret = 0;
    int iovlen = 0;
    void* iovbase;
    size_t copied = 0, alen;
    for(int i=0;i<iovcnt;i++){
        iovlen = iov[i].iov_len;
        iovbase = iov[i].iov_base;
        while(iovlen != 0){
            if ((alen = IOBUF_SIZE) > iovlen) {
                alen = iovlen;
            }
            ret = file_read(fd, buffer, alen, &alen);
            if(alen != 0){
                lock_mm(mm);
                {
                    if (copy_to_user(mm, iovbase, buffer, alen)) {
                        assert(iovlen >= alen);
                        iovbase += alen, iovlen -= alen, copied += alen;
                    }
                    else if (ret == 0) {
                        ret = -E_INVAL;
                    }
                }
                unlock_mm(mm);
            }
            if(ret != 0 || alen == 0){
                break;
            }
        }
    }
    kfree(buffer);
    if (copied != 0) {
        return copied;
    }
    return ret;
}

int
sysfile_write(int fd, void *base, size_t len) {
    struct mm_struct *mm = current->mm;
    if (len == 0) {
        return 0;
    }
    if (!file_testfd(fd, 0, 1)) {
        return -E_INVAL;
    }
    void *buffer;
    if ((buffer = kmalloc(IOBUF_SIZE)) == NULL) {
        return -E_NO_MEM;
    }

    int ret = 0;
    size_t copied = 0, alen;
    while (len != 0) {
        if ((alen = IOBUF_SIZE) > len) {
            alen = len;
        }
        lock_mm(mm);
        {
            if (!copy_from_user(mm, buffer, base, alen, 0)) {
                ret = -E_INVAL;
            }
        }
        unlock_mm(mm);
        if (ret == 0) {
            ret = file_write(fd, buffer, alen, &alen);
            if (alen != 0) {
                assert(len >= alen);
                base += alen, len -= alen, copied += alen;
            }
        }
        if (ret != 0 || alen == 0) {
            goto out;
        }
    }

out:
    kfree(buffer);
    if (copied != 0) {
        return copied;
    }
    return ret;
}

