int 
sysfile_sendfile(int out_fd, int in_fd, off_t offset, size_t len){
    struct mm_struct *mm = current->mm;
    if (len == 0) {
        return 0;
    }
    if (!file_testfd(out_fd, 0, 1) || !file_testfd(in_fd, 1, 0)) {
        return -E_INVAL;
    }

    void *buffer;
    if ((buffer = kmalloc(IOBUF_SIZE)) == NULL) {
        return -E_NO_MEM;
    }

    int ret = 0;
    size_t copied = 0, alen;
    if(offset){
        file_seek(in_fd, offset, LSEEK_SET);
    }
    while(len != 0){
        if ((alen = IOBUF_SIZE) > len) {
            alen = len;
        }
        ret = file_read(in_fd, buffer, alen, &alen);
        if(alen != 0){
            int wret = file_write(out_fd, buffer, alen, &alen);
            assert(len >= alen);
            copied += alen; len -= alen;
        }
        if(ret != 0 || alen == 0){
            goto out;
        }
    }
out:
    kfree(buffer);
    if (copied != 0) {
        return copied;
    }
    return ret;
}

