vfs_lookupat(struct inode *dir, char* path, struct inode **node_store) {
    int ret;
    if (*path != '\0') {
        ret = vop_lookup(dir, path, node_store);
        //cprintf("in vfs_lookup. node_store:%d\n", (*node_store)->in_info.__sfs_inode_info.ino);
        return ret;
    }
    *node_store = dir;
    return 0;
}

int
vfs_lookup_parent(char *path, struct inode **node_store, char **endp){
    int ret;
    struct inode *node;
    if ((ret = get_device(path, &path, &node)) != 0) {
        return ret;
    }
    if (*path != '\0'){
        int pathlen = strlen(path);
        for(int i=pathlen-1;i>=0;i--){
            if(*(path+i) == '/'){
                assert(i < pathlen-1);
                (*endp) = path+i+1;
                *(path+i) = '\0';
                ret = vop_lookup(node, path, node_store);
                vop_ref_dec(node);
                return ret;
            }
        }
        // if no '/' then the device's inode should be parent
        *node_store = node;
        *endp = path;
    }
    return ret;
}

