        return 0;
    }
    return -E_NOENT;
}

int
vfs_set_curdir(struct inode *dir) {
    int ret = 0;
    lock_cfs();
    struct inode *old_dir;
    if ((old_dir = get_cwd_nolock()) != dir) {
        //cprintf("in vfs_set_curdir. dir:%d\n", dir->in_info.__sfs_inode_info.ino);
        if (dir != NULL) {
            uint32_t type;
            if ((ret = vop_gettype(dir, &type)) != 0) {
                goto out;
            }
            if (!S_ISDIR(type)) {
                ret = -E_NOTDIR;
                goto out;
            }
            vop_ref_inc(dir);
        }
        set_cwd_nolock(dir);
        //cprintf("in vfs_set_curdir. cd:%d\n", current->filesp->pwd->in_info.__sfs_inode_info.ino);
        if (old_dir != NULL) {
            vop_ref_dec(old_dir);
        }
    }
out:
    unlock_cfs();
    return ret;
}

