int
vfs_getcwd(struct iobuf *iob) {
    int ret;
    struct inode *node;
    if ((ret = vfs_get_curdir(&node)) != 0) {
        return ret;
    }
    assert(node->in_fs != NULL);

    const char *devname = vfs_get_devname(node->in_fs);
    if ((ret = iobuf_move(iob, (char *)devname, strlen(devname), 1, NULL)) != 0) {
        goto out;
    }
    char colon = ':';
    if ((ret = iobuf_move(iob, &colon, sizeof(colon), 1, NULL)) != 0) {
        goto out;
    }
    //cprintf("in vfs_getcwd. node:%d\n", node->in_info.__sfs_inode_info.ino);
    ret = vop_namefile(node, iob);

out:
    vop_ref_dec(node);
    return ret;
}

int
vfs_mkdir(char *path, int64_t dir_flags){
    int ret;
    struct inode *node;
    if ((ret = vfs_lookup(path, &node)) == 0) { // if find the dict, do nothing
        vop_ref_dec(node);
        return ret;
    }

    if (ret != 0) {
        if(ret == -16){     // no such dictionary, then create it
            char *name;
            struct inode *dir;
            if ((ret = vfs_lookup_parent(path, &dir, &name)) != 0) {
                return ret;
            }
            //cprintf("in vfs_mkdir. parent_inode:%d, name:%s\n", dir->in_info.__sfs_inode_info.ino, name);
            //cprintf("in vfs_mkdir. createdir:%d\n", dir->in_ops->vop_createdir);
            ret = vop_createdir(dir, name, dir_flags, &node);
            vop_ref_dec(dir);
        } 
        else
            goto exit;
    }
    assert(node != NULL);
exit:
    return ret;
}

