static void
check_swap(void)
{
    //backup mem env
     int ret, count = 0, total = 0, i;
     list_entry_t *le = &free_list;
     while ((le = list_next(le)) != &free_list) {
        struct Page *p = le2page(le, page_link);
        assert(PageProperty(p));
        count++, total += p->property;
     }
     assert(total == nr_free_pages());
     cprintf("BEGIN check_swap: count %d, total %d\n", count, total);

     //now we set the phy pages env     
     struct mm_struct *mm = mm_create();
     assert(mm != NULL);

     extern struct mm_struct *check_mm_struct;
     assert(check_mm_struct == NULL);

     check_mm_struct = mm;

     pde_t *pgdir = mm->pgdir = boot_pgdir;
     assert(pgdir[3] == 0);

     struct vma_struct *vma = vma_create(BEING_CHECK_VALID_VADDR, CHECK_VALID_VADDR, VM_WRITE | VM_READ);
     assert(vma != NULL);

     insert_vma_struct(mm, vma);

     //setup the temp Page Table vaddr 0~4MB
     cprintf("setup Page Table for vaddr 0XC0001000, so alloc two pages\n");
     pte_t *temp_ptep = NULL;
     temp_ptep = get_pte(mm->pgdir, BEING_CHECK_VALID_VADDR, 1);
     assert(temp_ptep != NULL);
     cprintf("setup Page Table vaddr 0~4MB OVER!\n");

     for (i = 0; i < CHECK_VALID_PHY_PAGE_NUM; i++) {
          check_rp[i] = alloc_page();
          assert(check_rp[i] != NULL );
          assert(!PageProperty(check_rp[i]));
     }
     list_entry_t free_list_store = free_list;
     list_init(&free_list);
     assert(list_empty(&free_list));

     //assert(alloc_page() == NULL);

     unsigned int nr_free_store = nr_free;
     nr_free = 0;
     for (i = 0; i < CHECK_VALID_PHY_PAGE_NUM; i++) {
        free_pages(check_rp[i], 1);
     }
     assert(nr_free == CHECK_VALID_PHY_PAGE_NUM);

     cprintf("set up init env for check_swap begin!\n");
     //setup initial vir_page<->phy_page environment for page relpacement algorithm 


     pgfault_num = 0;

     check_content_set();
     assert(nr_free == 0);
     for(i = 0; i < MAX_SEQ_NO ; i++)
         swap_out_seq_no[i] = swap_in_seq_no[i] = -1;

     for (i = 0; i < CHECK_VALID_PHY_PAGE_NUM; i++) {
         check_ptep[i] = 0;
         check_ptep[i] = get_pte(pgdir, BEING_CHECK_VALID_VADDR + i * 0x1000, 0);
         //cprintf("i %d, check_ptep addr %x, value %x\n", i, check_ptep[i], *check_ptep[i]);
         assert(check_ptep[i] != NULL);
         assert(pte2page(*check_ptep[i]) == check_rp[i]);
         assert((*check_ptep[i] & PTE_V));          
     }
     cprintf("set up init env for check_swap over!\n");
     // now access the virt pages to test  page relpacement algorithm 
     ret = check_content_access();
     assert(ret == 0);

     nr_free = nr_free_store;
     free_list = free_list_store;

     //restore kernel mem env
     for (i = 0; i < CHECK_VALID_PHY_PAGE_NUM; i++) {
         free_pages(check_rp[i], 1);
     } 

     //free_page(pte2page(*temp_ptep));

     mm->pgdir = NULL;
     mm_destroy(mm);
     check_mm_struct = NULL;

     pde_t *pd1 = pgdir, *pd0 = page2kva(pde2page(boot_pgdir[3]));
     free_page(pde2page(pd0[0]));
     free_page(pde2page(pd1[3]));
     pgdir[3] = 0;
     flush_tlb();

     le = &free_list;
     while ((le = list_next(le)) != &free_list) {
         struct Page *p = le2page(le, page_link);
         count --, total -= p->property;
     }
     assert(count == 0);
     assert(total == 0);

     cprintf("check_swap() succeeded!\n");
}

struct swap_manager
{
     const char *name;
