int
do_wait(int pid, int *code_store) {
    struct mm_struct *mm = current->mm;
    if (code_store != NULL) {
        if (!user_mem_check(mm, (uintptr_t)code_store, sizeof(int), 1)) {
            return -E_INVAL;
        }
    }

    struct proc_struct *proc;
    bool intr_flag, haskid;
repeat:
    haskid = 0;
    if (pid != 0) {
        proc = find_proc(pid);
        if (proc != NULL && proc->parent == current) {
            haskid = 1;
            if (proc->state == PROC_ZOMBIE) {
                goto found;
            }
        }
    }
    else {
        proc = current->cptr;
        for (; proc != NULL; proc = proc->optr) {
            haskid = 1;
            if (proc->state == PROC_ZOMBIE) {
                goto found;
            }
        }
    }
    if (haskid) {
        current->state = PROC_SLEEPING;
        current->wait_state = WT_CHILD;
        schedule();
        if (current->flags & PF_EXITING) {
            do_exit(-E_KILLED);
        }
        goto repeat;
    }
    return -E_BAD_PROC;

found:
    if (proc == idleproc || proc == initproc) {
        panic("wait idleproc or initproc.\n");
    }
    if (code_store != NULL) {
        *code_store = proc->exit_code;
    }
    int idp = proc->pid;
    local_intr_save(intr_flag);
    {
        unhash_proc(proc);
        remove_links(proc);
    }
    local_intr_restore(intr_flag);
    put_kstack(proc);
    kfree(proc);
    return idp;
}

int
do_kill(int pid) {
    struct proc_struct *proc;
    if ((proc = find_proc(pid)) != NULL) {
        if (!(proc->flags & PF_EXITING)) {
            proc->flags |= PF_EXITING;
            if (proc->wait_state & WT_INTERRUPTED) {
                wakeup_proc(proc);
            }
            return 0;
        }
        return -E_KILLED;
    }
    return -E_INVAL;
}

int
do_brk(uintptr_t *brk_store){
    struct mm_struct *mm = current->mm;
    if (mm == NULL) {
        panic("kernel thread call sys_brk!!.\n");
    }

    uintptr_t brk;
    lock_mm(mm);    //we need to alloc brk
    if(brk_store == 0){
        brk = 0;
    }
    else{
        if (!copy_from_user(mm, &brk, brk_store, sizeof(uintptr_t), 1)) {
            unlock_mm(mm);
            cprintf("[do_brk]copy_fault\n");
            return -E_INVAL;
        }
    }
    uintptr_t oldbrk = mm->brk;
    uintptr_t newbrk = ROUNDUP(brk, PGSIZE);
    assert(oldbrk % PGSIZE == 0);
    if(oldbrk == newbrk || newbrk == 0){   // if newbrk == 0 return oldbrk
        *brk_store = oldbrk;
        unlock_mm(mm);
        return 0;
    }
    assert(newbrk > oldbrk);
    if (find_vma_intersection(mm, oldbrk, newbrk + PGSIZE) != NULL) {
        goto out_unlock;
    }
    if (mm_brk(mm, oldbrk, newbrk - oldbrk) != 0) {
        goto out_unlock;
    }
    mm->brk = newbrk;
out_unlock:
    *brk_store = mm->brk;
    unlock_mm(mm);
    return 0;
out_failed:
    unlock_mm(mm);
    return 0;
}

static int
kernel_execve(const char *name, const char **argv) {
    int64_t argc = 0, ret;
    while (argv[argc] != NULL){
        cprintf("ke:argv[%d]%s\n", argc, argv[argc]);
        argc++;
    }
    asm volatile(
        "ld a0, %2\n"
        "ld a1, %3\n"
        "ld a2, %4\n"
   	    "li a7, %1\n"
        "ebreak\n"
        "sd a0, %0\n"
        : "=m"(ret)
        : "i"(SYS_exec), "m"(name), "m"(argc), "m"(argv)
        : "memory");
//    cprintf("ret = %d\n", ret);
    return ret;
}

