static int
sys_clock_gettime(uint64_t arg[]) {
    int clockid = (int)arg[0];
    struct timespec * clock = (struct timespec *)arg[1];
    switch(clockid){
        case CLOCK_REALTIME:
            clock->tv_sec = (timebase+ticks)/100;
            clock->tv_nsec = (ticks % 100) * 10E9;
            return (timebase+ticks) * 10;
        case CLOCK_MONOTONIC:
            clock->tv_sec = ticks / 100;
            clock->tv_nsec = (ticks % 100) * 10E9;
            return ticks * 10;
        default:
            break;
    }
    return (timebase+ticks) * 10;

}

