void
syscall(void) {
    struct trapframe *tf = current->tf;
    uint64_t arg[5];
    int num = tf->gpr.a7;
    //cprintf("in kernel syscall. num:%d\n", num);
    if (num >= 0 && num < NUM_SYSCALLS) {
        if (syscalls[num] != NULL) {
            arg[0] = tf->gpr.a0;
            arg[1] = tf->gpr.a1;
            arg[2] = tf->gpr.a2;
            arg[3] = tf->gpr.a3;
            arg[4] = tf->gpr.a4;
            tf->gpr.a0 = syscalls[num](arg);
            return ;
        }
    }
    print_trapframe(tf);
    panic("undefined syscall %d, pid = %d, name = %s.\n",
            num, current->pid, current->name);
}

