int head_main(int argc, char **argv)
{
    argv++;
    argc--;
	unsigned long count = 1;
	int fp;
	const char *fmt;
	char *p;
	int opt;
	int retval = EXIT_SUCCESS;

	/* No size benefit in converting this to getopt32 */
	while ((opt = getopt(argc, argv, head_opts)) > 0) {
		switch (opt) {
            case 'n':
                p = optarg;
                break;
            default:
                bb_show_usage();
		}
	}

	argc -= optind;
	argv += optind;
	if (!*argv)
		*--argv = (char*)"-";

	fmt = header_fmt_str + 1;
	if (argc <= header_threshhold) {
		fmt += 11; /* "" */
	}

	do {
		fp = open(*argv, 0);
		if (fp > 0) {
			if (header_threshhold) {
				printf(fmt, *argv);
			}
			print_first_N(fp, count);
			if (!close(fp)) {
				retval = EXIT_FAILURE;
			}
		} else {
            printf("cannot open %s\n", *argv);
			retval = EXIT_FAILURE;
		}
		fmt = header_fmt_str;
	} while (*++argv);

	return retval;
}

