static void
initialize(iter_t iterations, void* cookie)
{
	char	c;
	state_t * state = (state_t *)cookie;

	if (pipe(state->p1) == -1) {
		perror("pipe");
		exit(1);
	}
	if (pipe(state->p2) == -1) {
		perror("pipe");
		exit(1);
	}
	switch (state->pid = fork()) {
	    case 0:
		close(state->p1[1]);
		close(state->p2[0]);
		//fprintf(STDERR, "child: p1(r):%d, p2(w):%d\n",state->p1[0], state->p2[1]);
		writer(state->p2[1], state->p1[0]);
		return;

	    case -1:
		perror("fork");
		return;

	    default:
		//fprintf(STDERR, "parent: p1(w):%d, p2(r):%d\n",state->p1[1], state->p2[0]);
		close(state->p1[0]);
		close(state->p2[1]);
		break;
	}

	/*
	 * One time around to make sure both processes are started.
	 */
	if (write(state->p1[1], &c, 1) != 1 || read(state->p2[0], &c, 1) != 1){
		perror("(i) read/write on pipe");
		exit(1);
	}
}

static void
cleanup(iter_t iterations, void* cookie)
{
	state_t * state = (state_t *)cookie;

	if (state->pid) {
		kill(state->pid);
		waitpid(state->pid, NULL, 0);
		state->pid = 0;
	}
}

static void
doit(register iter_t iterations, void *cookie)
{
	state_t *state = (state_t *) cookie;
	char		c;
	register int	w = state->p1[1];
	register int	r = state->p2[0];
	register char	*cptr = &c;
	int w0, r0;
	while (iterations-- > 0) {
		if ((w0=write(w, cptr, 1)) != 1 ||
		    (r0=read(r, cptr, 1)) != 1) {
			fprintf(STDERR, "(r) read/write on pipe, w:%d, r:%d", w0, r0);
			exit(1);
		}
	}
}

static void
writer(register int w, register int r)
{
	char		c;
	register char	*cptr = &c;
	int count = 0;
	for ( ;; ) {
		count++;
		if (read(r, cptr, 1) != 1 ||
			write(w, cptr, 1) != 1) {
			    perror("(w) read/write on pipe");
				exit(1);
		}
	}
}

static void
cleanup(iter_t iterations, void* cookie)
{
	if (iterations) return;

	if (child_pid) {
		kill(child_pid);
		waitpid(child_pid, NULL, 0);
		child_pid = 0;
	}
}

