static void
do_shell(iter_t iterations, void* cookie)
{
	while (iterations-- > 0) {
		switch (child_pid = fork()) {
		case -1:
			perror("fork");
			exit(1);

		case 0:	/* child */
			close(1);
			//execlp("/bin/sh", "sh", "-c", PROG, 0);
			exit(1);

		default:
			waitpid(child_pid, NULL,0);
		}
		child_pid = 0;
	}
}

static void
do_forkexec(iter_t iterations, void* cookie)
{
	char	*nav[2] = {PROG, 0};
	char	*nev[] = {NULL};
	while (iterations-- > 0) {
		switch (child_pid = fork()) {
		case -1:
			perror("fork");
			exit(1);

		case 0: 	/* child */
			//close(1);
			execve(PROG, nav, nev);
			exit(1);

		default:
			waitpid(child_pid, NULL,0);
		}
		child_pid = 0;
		if(iterations % 1000 == 0){
			perror("exec 1000 times.\n");
		}
	}
}

static void
do_fork(iter_t iterations, void* cookie)
{
	while (iterations-- > 0) {
		switch (child_pid = fork()) {
		case -1:
			perror("fork");
			exit(1);

		case 0:	/* child */
			exit(1);

		default:
			waitpid(child_pid, NULL,0);
		}
		child_pid = 0;
		if(iterations % 1000 == 0){
			perror("fork 1000 times.\n");
		}
	}
}

