struct {
        union header *ptr;
        size_t size;
        //bool type;          // 0: normal, sys_mybrk; 1: shared memory, shmem, now we don't support
    }

static inline void
lock_malloc(void) {
    lock_fork();
    lock(&mem_lock);
}

static inline void
unlock_malloc(void) {
    unlock(&mem_lock);
    unlock_fork();
}

static bool
brk_locked(size_t nu){
    static uintptr_t mybrk = 0;
    mybrk = brk(0);
    uintptr_t newbrk = mybrk + nu * sizeof(header_t);
    if (sys_brk(&newbrk) != 0 || newbrk <= mybrk) {
        return 0;
    }
    header_t *p = (void *)mybrk;
    p->s.size = (newbrk - mybrk) / sizeof(header_t);
    free_locked((void *)(p + 1));
    mybrk = newbrk;
    return 1;
}

static void *
malloc_locked(size_t size){
    static_assert(sizeof(header_t) == 0x40);
    header_t *p, *prevp;
    size_t nunits;

    nunits = (size + sizeof(header_t) - 1) / sizeof(header_t) + 1;  //按块分配内存，计算块数
    if ((prevp = freep) == NULL) {      // 初始化malloc机制
        base.s.ptr = freep = prevp = &base;
    }
    for (p = prevp->s.ptr; ; prevp = p, p = p->s.ptr) {     // 循环遍历malloc链
        if (p && p->s.size >= nunits) {
            if (p->s.size == nunits) {
                prevp->s.ptr = p->s.ptr;
            }
            else {
                header_t *np = prevp->s.ptr = (p + nunits);
                np->s.ptr = p->s.ptr;
                np->s.size = p->s.size - nunits;
                p->s.size = nunits;
            }
            freep = prevp;
            return (void *)(p + 1);
        }
        if (p == freep) {
            if (!brk_locked(nunits)) {
                return NULL;
            }
        }
    }
}

static void
free_locked(void *ap) {
    header_t *bp = ((header_t *)ap) - 1, *p;

    for (p = freep; !(bp > p && bp < p->s.ptr); p = p->s.ptr) {
        if (p >= p->s.ptr && (bp > p || bp < p->s.ptr)) {
            break;
        }
    }

    if (bp + bp->s.size == p->s.ptr) {
        bp->s.ptr = p->s.ptr->s.ptr;
    }
    else {
        bp->s.ptr = p->s.ptr;
    }

    if (p + p->s.size == bp) {
        p->s.ptr = bp->s.ptr;
    }
    else {
        p->s.ptr = bp;
    }

    freep = p;
}

void *
malloc(size_t size) {
    //printf("[malloc] size:%d\n", size);
    void *ret;
    lock_malloc();
    ret = malloc_locked(size);
    unlock_malloc();
    return ret;
}

void
free(void *ap) {
    lock_malloc();
    free_locked(ap);
    unlock_malloc();
}

int
getopt(int ac, char **av, char *opts)
{
	char	*t;

	if (!optind) {
		optind = 1;
		n = 1;
	}
	debug((STDERR, "GETOPT ind=%d n=%d arg=%s av[%d]='%s'\n",
	    optind, n, optarg ? optarg : "", optind, av[optind]));

	if ((optind >= ac) || (av[optind][0] != '-') || !av[optind][1]) {
		return (EOF);
	}

	assert(av[optind][n]);
	for (t = (char *)opts; *t; t++) {
		if (*t == av[optind][n]) {
			break;
		}
	}
	if (!*t) { 
		optopt = av[optind][n];
		debug((STDERR, "\tran out of option letters\n"));
		return ('?');
	}

	/* OK, we found a legit option, let's see what to do with it.
	 * If it isn't one that takes an option, just advance and return.
	 */
	if (t[1] != ':' && t[1] != '|' && t[1] != ';') {
		if (!av[optind][n+1]) {
			optind++;
			n = 1;
		} else {
			n++;
		}
		debug((STDERR, "\tLegit singleton %c\n", *t));
		return (*t);
	}

	/* got one with an option, see if it is cozied up to the flag */
	if (av[optind][n+1]) {
		if (av[optind][n+1]) {
			optarg = &av[optind][n+1];
		} else {
			optarg = 0;
		}
		optind++;
		n = 1;
		debug((STDERR, "\t%c with %s\n", *t, optarg));
		return (*t);
	} 

	/* If it was not there, and it is optional, OK */
	if (t[1] == '|') {
		optarg = 0;
		optind++;
		n = 1;
		debug((STDERR, "\t%c without arg\n", *t));
		return (*t);
	}

	/* was it supposed to be there? */
	if (t[1] == ';') {
		optarg = 0;
		optind++;
		optopt = *t;
		debug((STDERR, "\twanted another word\n"));
		return ('?');
	}

	/* Nope, there had better be another word. */
	if ((optind + 1 == ac) || (av[optind+1][0] == '-')) {
		optopt = av[optind][n];
		debug((STDERR, "\twanted another word\n"));
		return ('?');
	}
	optarg = av[optind+1];
	optind += 2;
	n = 1;
	debug((STDERR, "\t%c with arg %s\n", *t, optarg));
	return (*t);
}

