int strcasecmp(const char* str1, const char* str2)
{
	while (*str1 != '\0' && *str2 != '\0')
	{
		if (*str1 != *str2)
		{
			if (((*str1 > 'a' || *str1 < 'z') && (*str1 - 'a' == *str2 - 'A')) ||
				((*str1 > 'A' || *str1 < 'Z') && (*str1 - 'A' == *str2 - 'a')))
			{
				str1++;
				str2++;				
			}
			else
			{
				break;
			}

		}
		else
		{
			str1++;
			str2++;
		}
	}
	return *str1 - *str2;
}

double atof(const char* str)
{
double numres = 0.0;
    double intpart = 0.0;
    int i = 0;
    int afterdot = 0; // 判断到没到小数点
    int dotplace = 0;
    int number = 1; // 判断是不是数字
    int neg = 0;
    while (str[i] != '\0')
    {
        if (i == 0 && str[i] == '-')
        {
            neg = 1;
            i++;
            continue;
        }
        else if (i == 0 && str[i] == '+')
        {
            neg = 0;
            i++;
            continue;
        }
        if (str[i] <= '9' && str[i] >= '0')
        {
            if (!afterdot)
            {
                intpart = intpart * 10 + (str[i] - '0');
            }
            else
            {
                double temp = (str[i] - '0');
                for (int j = 0; j < i - dotplace; j++)
                {
                    temp /= 10;
                }
                numres += temp;
            }
        }
        else if (str[i] == '.')
        {
            afterdot = 1;
            dotplace = i;
        }
        else
        {
            if (str[i + 1] != '\0')
            {
                number = 0;
                break;
            }
        }
        i++;

    }

    if (!number)
    {
        return 0.0;
    }
    else
    {
        numres += intpart;
        if (neg)
        {
            numres = (-1) * numres;
        }
        return numres;
    }
}

char *getenv(const char *name)
{
  register int len = strlen(name);
  register char **ep;


  if (__environ == NULL)
    return NULL;


  for (ep = __environ; *ep != NULL; ++ep)
    if (!strncmp(*ep, name, len) && (*ep)[len] == '=')
      return &(*ep)[len + 1];


  return NULL;
}

